from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)

# Set up OpenID Connect provider information
provider_url = "https://example.com"
client_id = "your-client-id"
redirect_uri = "http://localhost:5000/callback"

@app.route("/")
def index():
    # Redirect to the OpenID Connect provider's /authorize endpoint
    authorization_url = f"{provider_url}/authorize?response_type=code&client_id={client_id}&redirect_uri={redirect_uri}"
    return redirect(authorization_url)

@app.route("/callback")
def callback():
    # Exchange the authorization code for tokens
    code = request.args.get("code")
    token_response = requests.post(f"{provider_url}/token", data={
        "grant_type": "authorization_code",
        "client_id": client_id,
        "redirect_uri": redirect_uri,
        "code": code
    })
    tokens = token_response.json()

    # Decode the id_token to get user claims
    id_token = tokens["id_token"]
    decoded_token = requests.post(f"{provider_url}/token/introspect", data={
        "token": id_token,
        "client_id": client_id,
        "redirect_uri": redirect_uri
    })
    user_claims = decoded_token.json()["user"]

    # Store user information in the session
    session["user"] = user_claims

    return "Logged in"